import { IMessageComposer } from '@nitrots/nitro-renderer';

export class TradeAddItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(sessionId: number, inventoryRowId: number, quantity: number, slotIndex: number)
{
// Must match TradeAddItemEvent.java order
this._data = [
sessionId,
inventoryRowId,
quantity,
slotIndex
];

console.log('Packet TradeAddItemComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}
